<tr><th scope="row">5th</th><td><em>charm monster</em></td></tr>
<tr><th scope="row">6th</th><td><em>geas/quest</em></td></tr>
<tr><th scope="row">7th</th><td><em>insanity</em></td></tr>
<tr><th scope="row">8th</th><td><em>demand</em></td></tr>
<tr><th scope="row">9th</th><td><em>dominate monster</em></td></tr></tbody></table><h3 id="domain-charm-love-subdomain" data-hash-target>Love Subdomain</h3>
